// Package pbs groups the typed, generated bindings for the Proxmox
// Backup Server REST API. Each child package (access, admin, config,
// nodes, tape, …) is generated by cmd/pvegen from
// _data/pbs-apidoc.json and exposes a Service interface plus typed
// request/response shapes.
//
// PBS shares the PVE wire conventions (/api2/json base path,
// /access/ticket login, CSRFPreventionToken header) but listens on
// port 8007 and uses the PBSAPIToken/PBSAuthCookie credential names;
// see DefaultOptions in options.go for a preconfigured pkg/client
// Options value.
//
// Do not add hand-written code at this directory level beyond the
// client preset; everything else is metadata so that
// `go generate ./...` has a stable home.
package pbs

//go:generate go run ../../cmd/pvegen --dialect pbs --spec ../../_data/pbs-apidoc.json --out .
